# Core entity types - classes and structs

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_from_origin(self) -> float:
        return pow(self.x ** 2 + self.y ** 2, 0.5)

class Person:
    name: str
    age: int

    def __init__(self, name: str, age: int):
        self.name = name
        self.age = age

    def greet(self) -> str:
        return f"Hello, I'm {self.name}!"

    @virtual
    def describe(self) -> str:
        return f"{self.name}, age {self.age}"

class Employee(Person):
    employee_id: int
    department: str

    def __init__(self, name: str, age: int, emp_id: int, dept: str):
        super().__init__(name, age)
        self.employee_id = emp_id
        self.department = dept

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base} (Employee #{self.employee_id} in {self.department})"

