# Business logic services

from entities import Point

enum Status:
    PENDING = 0
    ACTIVE = 1
    COMPLETED = 2

class Task:
    title: str
    status: Status
    location: Point

    def __init__(self, title: str, loc: Point):
        self.title = title
        self.status = Status.PENDING
        self.location = loc

    def mark_complete(self) -> None:
        self.status = Status.COMPLETED

    def get_summary(self) -> str:
        status_name: str = "Unknown"
        if self.status == Status.PENDING:
            status_name = "Pending"
        elif self.status == Status.ACTIVE:
            status_name = "Active"
        elif self.status == Status.COMPLETED:
            status_name = "Completed"
        return f"{self.title} [{status_name}]"

class DataProcessor:
    items: list[int]

    def __init__(self):
        self.items = []

    def add_item(self, x: int) -> None:
        self.items.append(x)

    def get_average(self) -> float:
        if len(self.items) == 0:
            return 0.0
        total: int = sum(self.items)
        return float(total) / len(self.items)

    def get_max(self) -> int:
        if len(self.items) == 0:
            return 0
        return max(self.items)
